func TestSpanContext_Traceparent(t *testing.T) {
	tc := NewTraceContext()
	span := tc.NewSpan()
	tp := span.Traceparent()
	// Format: 00-{traceID32}-{spanID16}-{flags2}
	pattern := `^00-[0-9a-f]{32}-[0-9a-f]{16}-01$`
	matched, err := regexp.MatchString(pattern, tp)
	if err != nil {
		t.Fatalf("regex error: %v", err)
