33		upgradeReq := fmt.Sprintf("GET %s HTTP/1.1\r\nHost: %s\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Key: %s\r\nSec-WebSocket-Version: 13\r\n%s\r\n", path, host, clientKey, hdrs.String())
34		conn.SetDeadline(time.Now().Add(timeout))
35		conn.Write([]byte(upgradeReq))
36	
37		buf := make([]byte, 4096)
38		n, err := conn.Read(buf)
39		if err != nil {
40			return fmt.Errorf("read upgrade response: %w", err)
41		}
42	
43		resp := string(buf[:n])
44		if !strings.Contains(resp, " 101 ") {
45			return fmt.Errorf("upgrade failed: %s", strings.Split(resp, "\r\n")[0])
46		}
47	
48		// Verify accept key
49		expectedAccept := computeAcceptKey(clientKey)
50		if !strings.Contains(resp, expectedAccept) {
51			return fmt.Errorf("invalid accept key")
52		}
53	
54		return nil
55	}
