63	// wsReadFrame reads a single WebSocket frame and returns the payload as a string.
64	// Handles text (opcode 1), binary (opcode 2), close (opcode 8), and ping (opcode 9).
65	func wsReadFrame(conn net.Conn) (string, bool, error) {
66		header := make([]byte, 2)
67		if _, err := io.ReadFull(conn, header); err != nil {
68			return "", false, fmt.Errorf("read frame header: %w", err)
69		}
70	
71		opcode := header[0] & 0x0F
72		masked := (header[1] & 0x80) != 0
73		payloadLen := int64(header[1] & 0x7F)
74	
75		switch payloadLen {
76		case 126:
77			ext := make([]byte, 2)
78			if _, err := io.ReadFull(conn, ext); err != nil {
79				return "", false, err
80			}
81			payloadLen = int64(binary.BigEndian.Uint16(ext))
82		case 127:
83			ext := make([]byte, 8)
84			if _, err := io.ReadFull(conn, ext); err != nil {
85				return "", false, err
86			}
87			payloadLen = int64(binary.BigEndian.Uint64(ext))
88		}
89	
90		// Skip mask key if present (server frames should not be masked, but handle it)
91		if masked {
92			mask := make([]byte, 4)
93			if _, err := io.ReadFull(conn, mask); err != nil {
94				return "", false, err
95			}
96		}
97	
98		if opcode == 0x08 {
99			// Close frame
100			reason := ""
101			if payloadLen > 0 {
102				payload := make([]byte, payloadLen)
103				if _, err := io.ReadFull(conn, payload); err != nil {
104					return "", true, err
105				}
106				reason = string(payload)
107			}
108			return reason, true, nil
109		}
110	
111		if opcode == 0x09 {
112			// Ping — read payload, ignore (no pong response in this minimal client)
113			if payloadLen > 0 {
114				payload := make([]byte, payloadLen)
115				if _, err := io.ReadFull(conn, payload); err != nil {
116					return "", false, err
117				}
118			}
119			return "", false, nil
120		}
121	
122		// Text (1) or Binary (2) — read payload
123		var payload []byte
124		if payloadLen > 0 {
125			payload = make([]byte, payloadLen)
126			if _, err := io.ReadFull(conn, payload); err != nil {
127				return "", false, err
128			}
129		}
130	
131		return string(payload), false, nil
132	}
133	
134	// wsSendMessage writes a masked text frame (required by RFC 6455 for client frames).
135	func wsSendMessage(conn net.Conn, msg string) error {
136		frame := []byte{0x81} // FIN + text opcode
137		msgLen := len(msg)
138		if msgLen <= 125 {
139			frame = append(frame, byte(0x80|msgLen))
140		} else if msgLen <= 65535 {
141			frame = append(frame, 0x80|126)
142			frame = append(frame, byte(msgLen>>8), byte(msgLen))
143		} else {
144			frame = append(frame, 0x80|127)
145			for i := 7; i >= 0; i-- {
146				frame = append(frame, byte(msgLen>>(i*8)))
147			}
148		}
149	
150		mask := make([]byte, 4)
151		rand.Read(mask)
152		frame = append(frame, mask...)
153	
154		masked := make([]byte, msgLen)
155		for i, b := range []byte(msg) {
156			masked[i] = b ^ mask[i%4]
157		}
158		frame = append(frame, masked...)
159	
160		_, err := conn.Write(frame)
161		return err
162	}
